import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import './Navbar.css'; // CSS फाईल इथे जोडली आहे

const Navbar = () => {
  const navigate = useNavigate();
  const token = localStorage.getItem('token'); 

  const handleLogout = () => {
    localStorage.removeItem('token');
    alert("यशस्वीरीत्या बाहेर पडला आहात!");
    navigate('/login');
  };

  return (
    <nav className="navbar-container">
      <div className="logo">
        <Link to="/" className="logo-link">Nexus<span>.</span></Link>
      </div>

      <div className="nav-links">
        <Link to="/services" className="nav-item">Services</Link>
        <Link to="/marketplace" className="nav-item">Marketplace</Link>

        {token ? (
          <>
            <Link to="/dashboard" className="nav-item">Dashboard</Link>
            <button onClick={handleLogout} className="logout-btn">Logout</button>
          </>
        ) : (
          <Link to="/login" className="join-btn">Join Us</Link>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
